  1→package scraper
  2→
  3→import (
  4→	"encoding/json"
  5→	"errors"
  6→	"fmt"
  7→	"os"
  8→	"path/filepath"
  9→	"time"
 10→)
 11→
 12→// Sentinel errors for cache operations.
 13→var (
 14→	ErrNotFound = errors.New("scraper: cache entry not found")
 15→	ErrStale    = errors.New("scraper: cache entry is stale")
 16→)
 17→
 18→// cacheEntry is the JSON structure stored on disk.
 19→type cacheEntry struct {
 20→	ScrapedAt    string   `json:"scraped_at"`
 21→	Institutions []string `json:"institutions"`
 22→}
 23→
 24→// Cache stores and retrieves scraped institution name lists as JSON files.
 25→type Cache struct {
 26→	dir    string
 27→	maxAge time.Duration
 28→}
 29→
 30→// NewCache creates a cache that stores files under dir with the given
 31→// staleness threshold.
 32→func NewCache(dir string, maxAge time.Duration) *Cache {
 33→	return &Cache{dir: dir, maxAge: maxAge}
 34→}
 35→
 36→// cacheDir returns the directory for admissions cache files.
 37→func (c *Cache) cacheDir() string {
 38→	return filepath.Join(c.dir, "admissions")
 39→}
 40→
 41→// filename returns the cache file path for a platform and date.
 42→func (c *Cache) filename(platform string, date time.Time) string {
 43→	return filepath.Join(c.cacheDir(), fmt.Sprintf("%s-%s.json", platform, date.Format("2006-01-02")))
 44→}
 45→
 46→// Save writes the institution names to a dated cache file.
 47→func (c *Cache) Save(platform string, names []string) error {
 48→	dir := c.cacheDir()
 49→	if err := os.MkdirAll(dir, 0o755); err != nil {
 50→		return fmt.Errorf("scraper: cache mkdir: %w", err)
 51→	}
 52→
 53→	now := time.Now()
 54→	entry := cacheEntry{
 55→		ScrapedAt:    now.Format(time.RFC3339),
 56→		Institutions: names,
 57→	}
 58→
 59→	data, err := json.MarshalIndent(entry, "", "  ")
 60→	if err != nil {
 61→		return fmt.Errorf("scraper: cache marshal: %w", err)
 62→	}
 63→
 64→	path := c.filename(platform, now)
 65→	if err := os.WriteFile(path, data, 0o644); err != nil {
 66→		return fmt.Errorf("scraper: cache write: %w", err)
 67→	}
 68→	return nil
 69→}
 70→
 71→// Load reads the most recent cache file for the given platform. Returns
 72→// ErrNotFound if no file exists, or ErrStale if the newest file is older
 73→// than maxAge.
 74→func (c *Cache) Load(platform string) ([]string, error) {
 75→	dir := c.cacheDir()
 76→	entries, err := os.ReadDir(dir)
 77→	if err != nil {
 78→		if os.IsNotExist(err) {
 79→			return nil, ErrNotFound
 80→		}
 81→		return nil, fmt.Errorf("scraper: cache readdir: %w", err)
 82→	}
 83→
 84→	// Find the newest matching file by sorting lexically (date in filename).
 85→	prefix := platform + "-"
 86→	var newest string
 87→	for _, e := range entries {
 88→		name := e.Name()
 89→		if len(name) > len(prefix) && name[:len(prefix)] == prefix && filepath.Ext(name) == ".json" {
 90→			if name > newest {
 91→				newest = name
 92→			}
 93→		}
 94→	}
 95→	if newest == "" {
 96→		return nil, ErrNotFound
 97→	}
 98→
 99→	path := filepath.Join(dir, newest)
100→	data, err := os.ReadFile(path)
101→	if err != nil {
102→		return nil, fmt.Errorf("scraper: cache read: %w", err)
103→	}
104→
105→	var entry cacheEntry
106→	if err := json.Unmarshal(data, &entry); err != nil {
107→		return nil, fmt.Errorf("scraper: cache unmarshal: %w", err)
108→	}
109→
110→	scrapedAt, err := time.Parse(time.RFC3339, entry.ScrapedAt)
111→	if err != nil {
112→		return nil, fmt.Errorf("scraper: cache parse time: %w", err)
113→	}
114→	if time.Since(scrapedAt) > c.maxAge {
115→		return nil, ErrStale
116→	}
117→
118→	return entry.Institutions, nil
119→}
